190→func generateSchema[T any]() anthropic.ToolInputSchemaParam {
191→	reflector := jsonschema.Reflector{
192→		AllowAdditionalProperties: false,
193→		DoNotReference:            true,
194→	}
195→	var v T
196→	schema := reflector.Reflect(v)
197→	return anthropic.ToolInputSchemaParam{
198→		Properties: schema.Properties,
199→	}
200→}
